SELECT COUNT(*)
FROM posts p
WHERE p.board_id = #{boardId}
  AND p.status = 'ACTIVE'

    AND p.category_code = #{categoryCode}

SELECT COUNT(*)
FROM post_likes
WHERE post_id = #{postId}
  AND user_id = #{userId}

