mapper.select:
SELECT


WHERE p.board_id = #{boardId}
  AND p.status = 'ACTIVE'
  AND p.created_at >= #{startAt}

    AND p.category_code = #{categoryCode}

ORDER BY
  p.pinned DESC,
  p.like_count DESC,
  p.comment_count DESC,
  p.created_at DESC,
  p.id DESC
LIMIT #{limit}
